payload.cmd:
node - << 'EOF'
const fs = require('fs');
const { execFileSync } = require('child_process');
const path = '.sofar/initiatives/harness-build/events.jsonl';
const evs = fs.readFileSync(path, 'utf8').trim().split('\n').map(JSON.parse);
const plans = evs.filter(e => e.type === 'plan_updated');
const bad = plans[plans.length - 1];      // my Phase-10-only clobber
const good = plans[plans.length - 2];     // last full plan (Phase 9 rename era)

if (bad.payload.plan.phases.length !== 1) throw new Error('bad plan sanity check failed');
console.log('bad plan_updated id:', bad.id, '| phases in bad:', bad.payload.plan.phases.length);
console.log('good plan phases:', good.payload.plan.phases.map(p => p.name).join(' | '));

// Reconstruct full plan from the last-good snapshot: only Phase 9 advanced since
// (9.3 done, phase done), then append Phase 10. Phases 1-8 already correct
// (Phase 5 active w/ 5.2+5.3 pending; rest done).
const plan = JSON.parse(JSON.stringify(good.payload.plan));
const p9 = plan.phases.find(p => p.name.startsWith('Phase 9'));
if (!p9) throw new Error('Phase 9 not found in good plan');
p9.status = 'done';
for (const t of p9.tasks) t.status = 'done';

plan.phases.push({
  name: 'Phase 10 — Host-repo scanner defense',
  status: 'pending',
  tasks: [
    { id: '10.1', title: 'sofar init detects tree-wide scanners (Tailwind v4: tailwindcss>=4 in package.json) and prints the .sofar exclusion hint as final output', status: 'pending' },
    { id: '10.2', title: 'sofar doctor: audit host repo — wiring integrity, record health (no stub sessions), scanner hazards (Tailwind v4 without @source not .sofar)', status: 'pending' },
    { id: '10.3', title: 'sofar doctor --fix: opt-in insert of @source not exclusion after the tailwindcss import (computed relative path to .sofar), gated behind explicit flag', status: 'pending' },
    { id: '10.4', title: 'Acceptance: init hint fires only on Tailwind v4; doctor flags missing exclusion + passes clean repo; --fix inserts correct path, idempotent', status: 'pending' },
  ],
});

const sofar = (args) => execFileSync('sofar', args, { encoding: 'utf8' });

// 1. void the clobber (BD8: corrections void the target during replay)
sofar(['event', 'append', '--type', 'correction', '--actor', 'agent',
  '--payload', JSON.stringify({ ref: bad.id, reason: 'plan_updated is a full-structure replace (SPEC); the Phase 10-only append clobbered phases 1-9 in the fold. Voided; full plan re-emitted below.' })]);

// 2. re-emit the complete plan (phases 1-9 + Phase 10)
const out = sofar(['event', 'append', '--type', 'plan_updated', '--actor', 'human',
  '--payload', JSON.stringify({ plan })]);
console.log('re-emit:', out.trim());
console.log('total phases restored:', plan.phases.length);
EOF

echo "=== whoami ===" && npm whoami 2>&1 | tail -2
echo && echo "=== registry ===" && npm config get registry
echo && echo "=== auth token present in npmrc? ===" && (npm config get //registry.npmjs.org/:_authToken 2>/dev/null | grep -q . && echo "token configured" || echo "no token")
